const parsed = mermaid.parseMermaid('erDiagram\n  CUSTOMER {\n    string id\n  }')
if (!parsed.ok) return { error: parsed.error }
const er = mermaid.asEr(parsed.value)
if (!er) return { error: 'not-er' }
const mutated = mermaid.mutate(er, { kind: 'add_entity', id: 'ORDER', attributes: ['string id'] })
if (!mutated.ok) return { error: mutated.error }
const verified = mermaid.verifyMermaid(mutated.value)
if (!verified.ok) return { error: 'verify', warnings: verified.warnings }
return { source: mermaid.serializeMermaid(mutated.value) }

